  "task": "Disable Kernel Parameter for Accepting ICMP Redirects by Default on IPv4 Interfaces",
  "steps": [
    {
      "type": "read_file",
      "path": "/etc/sysctl.d/99-sysctl.conf"
    },
    {
      "type": "run_cmd",
      "command": "sed -i '/^net\\.ipv4\\.conf\\.default\\.accept_redirects/d' /etc/sysctl.d/99-sysctl.conf"
    },
    {
      "type": "run_cmd",
      "command": "echo 'net.ipv4.conf.default.accept_redirects = 0' >> /etc/sysctl.d/99-sysctl.conf"
    },
    {
      "type": "run_cmd",
      "command": "sysctl -w net.ipv4.conf.default.accept_redirects=0"
    },
    {
